create table rmais_ship_to_location (
    id           number generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache
    20 noorder nocycle nokeep noscale not null enable,
    location     varchar2(255 byte),
    legal_entity varchar2(255 byte),
    col003       varchar2(4000 byte),
